// Separate overdue vs next-week tasks
const overdueItems = $('Get Overdue').all();
const nextWeekItems = $('Get Next Week').all();

// --- OVERDUE SECTION ---
const priorityMap = { 4: 'P1', 3: 'P2', 2: 'P3', 1: 'P4' };
const now = new Date();

let overdueHtml = '';
const overdueTasks = overdueItems.map(item => {
  const t = item.json;
  const dueDate = t.due ? new Date(t.due.date) : null;
  const daysOverdue = dueDate ? Math.floor((now - dueDate) / 86400000) : 0;
  return { content: t.content, priority: t.priority || 1, daysOverdue, dueDate };
}).sort((a, b) => b.priority - a.priority || b.daysOverdue - a.daysOverdue);

if (overdueTasks.length > 0) {
  overdueHtml = overdueTasks.map(t =>
    `<tr><td style="padding:4px 8px;color:${t.priority >= 4 ? '#d1453b' : '#666'}">${priorityMap[t.priority] || 'P4'}</td><td style="padding:4px 8px">${t.content}</td><td style="padding:4px 8px;color:#d1453b">${t.daysOverdue}d overdue</td></tr>`
  ).join('');
} else {
  overdueHtml = '<tr><td colspan="3" style="padding:8px;color:#4caf50">No overdue tasks!</td></tr>';
}

// --- NEXT WEEK SECTION ---
const dayNames = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
const byDay = {};

for (const item of nextWeekItems) {
  const t = item.json;
  if (!t.due || !t.due.date) continue;
  const d = new Date(t.due.date);
  const dayLabel = dayNames[d.getDay()] + ' ' + (d.getMonth()+1) + '/' + d.getDate();
  if (!byDay[dayLabel]) byDay[dayLabel] = [];
  byDay[dayLabel].push(t.content);
}

let nextWeekHtml = '';
const sortedDays = Object.keys(byDay);
if (sortedDays.length > 0) {
  nextWeekHtml = sortedDays.map(day =>
    `<tr><td style="padding:4px 8px;font-weight:bold;vertical-align:top">${day}</td><td style="padding:4px 8px">${byDay[day].join('<br>')}</td></tr>`
  ).join('');
} else {
  nextWeekHtml = '<tr><td colspan="2" style="padding:8px;color:#999">No tasks scheduled for next week</td></tr>';
}

// --- P1 HEALTH CHECK ---
const allTasks = [...overdueItems, ...nextWeekItems];
const p1Count = allTasks.filter(i => i.json.priority === 4).length;
const p1Recommendation = p1Count > 5 ? 'OVERLOADED — reduce P1 count' : p1Count > 3 ? 'HIGH — review priorities' : 'OK';
const p1Color = p1Count > 5 ? '#d1453b' : p1Count > 3 ? '#f59e0b' : '#4caf50';

// --- BUILD EMAIL ---
const weekStart = new Date(now);
weekStart.setDate(now.getDate() - now.getDay());
const weekEnd = new Date(weekStart);
weekEnd.setDate(weekStart.getDate() + 6);
const fmt = d => `${d.toLocaleString('en-US', { month: 'short' })} ${d.getDate()}`;

const subject = `[Weekly Review] ${fmt(weekStart)}-${fmt(weekEnd)} — ${overdueTasks.length} overdue, ${nextWeekItems.length} next week`;

const html = `
<div style="font-family:Arial,sans-serif;max-width:600px;margin:0 auto">
  <h2 style="color:#333;border-bottom:2px solid #e44332;padding-bottom:8px">Weekly Review</h2>

  <h3 style="color:#d1453b">STILL OVERDUE (${overdueTasks.length} tasks)</h3>
  <table style="width:100%;border-collapse:collapse">${overdueHtml}</table>

  <h3 style="color:#4073ff;margin-top:20px">NEXT WEEK</h3>
  <table style="width:100%;border-collapse:collapse">${nextWeekHtml}</table>

  <h3 style="margin-top:20px">P1 HEALTH CHECK</h3>
  <table style="width:100%;border-collapse:collapse">
    <tr><td style="padding:4px 8px">Active P1 count:</td><td style="padding:4px 8px;font-weight:bold">${p1Count}</td></tr>
    <tr><td style="padding:4px 8px">Recommendation:</td><td style="padding:4px 8px;font-weight:bold;color:${p1Color}">${p1Recommendation}</td></tr>
  </table>

  <p style="color:#999;font-size:12px;margin-top:20px">Generated by n8n Weekly Review workflow</p>
</div>`;

return [{ json: { subject, html } }];
